-- UBI fee-emitting events grouped by protocol. One row per protocol.

WITH all_routes AS (
    -- route  1: swap/v4_hook
    SELECT
    1                                AS fee_route_id,
    'swap'                        AS protocol,
    'v4_hook'                            AS kind,
    block_time,
    block_number,
    tx_hash,
    contract_address                          AS event_contract_address
    FROM   {{blockchain}}.logs
    WHERE  topic0 = 0xbc242f5093768aa93572c8496fa881527bd1bbb323867dd5f420727783b4eead
      AND contract_address = 0xd7acb2708f0d12efd9f02326c98fc56971dfcd9a
