    block_time,
    block_number,
    tx_hash,
    contract_address                          AS event_contract_address
    FROM   {{blockchain}}.logs
    WHERE  topic0 = 0xe01bcae5c6f2b7cec9d50a7134a8ab35ac3cf8d770115e10a2662093abeb4988
      AND contract_address = 0x1291be112d480055dafd8a610b7d1e203891c274
    UNION ALL
    -- route  3: perps/trading_fee
    SELECT
