    FROM   {{blockchain}}.logs
    WHERE  topic0 = 0x156e588d1067ba3c8a6a7f4376ef70794f8afed114dc9d1421e054b65743e630
      AND contract_address = 0x3489745eff9525ccc3d8c648102fe2cf3485e228
    UNION ALL
    -- route 10: stable/minting_fee
    SELECT
    10                                AS fee_route_id,
    'stable'                        AS protocol,
    'minting_fee'                            AS kind,
    block_time,
    block_number,
    tx_hash,
    contract_address                          AS event_contract_address
    FROM   {{blockchain}}.logs
    WHERE  topic0 = 0xc91682597e50d783bf81329b763263cef72b0cda71f5e617e0bd4b4150f84403
      AND contract_address = 0x9eb52339b52e71b1efd5537947e75d23b3a7719b
    UNION ALL
    -- PENDING DEPLOY: source contract StableUBIFeeSplitter is not yet in op-stack/addresses.json
    -- route 11: stable/liquidation_penalty
    SELECT
    11                                AS fee_route_id,
