    tx_hash,
    contract_address                          AS event_contract_address
    FROM   {{blockchain}}.logs
    WHERE  topic0 = 0x5503d47cba7f0b1b3a1343b3831327875fe679575c535fdad0642a7e97973f65
      -- contract_address pending — event source (StocksUBIFeeSplitter) not yet deployed
    UNION ALL
    -- route 14: stocks/liquidation_remnant
    SELECT
    14                                AS fee_route_id,
    'stocks'                        AS protocol,
    'liquidation_remnant'                            AS kind,
    block_time,
    block_number,
    tx_hash,
    contract_address                          AS event_contract_address
    FROM   {{blockchain}}.logs
    WHERE  topic0 = 0xf8f449ed6ff79644d8e4e873d43862bed27d3d68aca8a0b36c94de61645df71f
      -- contract_address pending — event source (StocksUBIFeeSplitter) not yet deployed
)
SELECT
    protocol,
    COUNT(*)                                        AS fee_events,
    COUNT(DISTINCT fee_route_id)                    AS routes_seen,
    COUNT(DISTINCT tx_hash)                         AS unique_txs,
    MIN(block_time)                                 AS first_event,
    MAX(block_time)                                 AS last_event
FROM   all_routes
GROUP BY 1
ORDER BY fee_events DESC
